"use client";

import { Toggle as TogglePrimitive } from "@base-ui/react/toggle";
import * as stylex from "@stylexjs/stylex";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { toggleStyles } from "./toggle.styles";

export type ToggleVariant = "default" | "outline";
export type ToggleSize = "default" | "sm" | "lg";

export interface ToggleProps extends PropsWithStylex<TogglePrimitive.Props> {
  variant?: ToggleVariant;
  size?: ToggleSize;
  style?: stylex.StyleXStyles;
}

export function Toggle({
  children,
  style,
  variant = "default",
  size = "default",
  ...props
}: ToggleProps) {
  const variantStyle = variant === "outline" ? toggleStyles.outline : toggleStyles.default;
  const sizeStyle =
    size === "sm" ? toggleStyles.sm : size === "lg" ? toggleStyles.lg : toggleStyles.defaultSize;
  const toggleProps = stylex.props(toggleStyles.base, variantStyle, sizeStyle, style);
  return (
    <TogglePrimitive
      {...toggleProps}
      data-slot="toggle"
      {...props}
      render={(renderProps, toggleState) => {
        const pressedStyle =
          variant === "outline" ? toggleStyles.outlinePressed : toggleStyles.defaultPressed;
        const renderStyles = stylex.props(
          toggleStyles.base,
          variantStyle,
          sizeStyle,
          toggleState.pressed && pressedStyle,
          style,
        );
        return (
          <button {...renderProps} {...renderStyles}>
            {children}
          </button>
        );
      }}
    />
  );
}

import * as stylex from "@stylexjs/stylex";
import { dataRuleQueries, fontSize, fontWeight, spacing, theme } from "@/lib/theme/contract.stylex";

export const toggleStyles = stylex.create({
  base: {
    position: "relative",
    display: "inline-flex",
    flexShrink: 0,
    alignItems: "center",
    justifyContent: "center",
    gap: spacing.small,
    whiteSpace: "nowrap",
    borderStyle: "solid",
    borderWidth: 1,
    borderRadius: theme.borderRadius,
    fontWeight: fontWeight.medium,
    fontSize: fontSize.small,
    lineHeight: 1.4,
    cursor: "pointer",
    userSelect: "none",
    outline: "none",
    backgroundColor: "transparent",
    transition: "box-shadow 0.15s ease",
    ":focus-visible": {
      boxShadow: `0 0 0 2px ${theme.focusRing}`,
    },
    ":disabled": {
      pointerEvents: "none",
      opacity: 0.64,
    },
  },
  icon: {
    flexShrink: 0,
    width: spacing.medium,
    height: spacing.medium,
  },
  default: {
    borderColor: "transparent",
    color: theme.contentPrimary,
    backgroundColor: theme.backgroundSubtle,
  },
  defaultPressed: {
    backgroundColor: theme.background,
  },
  outline: {
    borderColor: {
      default: theme.border,
      [dataRuleQueries.dataPressed]: theme.borderStrong,
    },
    color: theme.contentPrimary,
    backgroundColor: theme.backgroundSubtle,
  },
  outlinePressed: {
    outlineWidth: "0px",
    backgroundColor: theme.surfaceOverlay,
  },
  sm: {
    height: spacing.large,
    minWidth: spacing.large,
    paddingLeft: spacing.small,
    paddingRight: spacing.small,
  },
  defaultSize: {
    height: spacing.large,
    minWidth: 36,
    paddingLeft: spacing.small,
    paddingRight: spacing.small,
  },
  lg: {
    height: spacing.xlarge,
    paddingLeft: spacing.medium,
    paddingRight: spacing.medium,
  },
});
